import {
	createDefaultState,
	detectSdCardFromListing,
	deriveSystemState,
	getBackendMountPath
} from './utils';
import type {
	CreateFileManagerActionsOptions,
	FileEntry,
	FileListResponse,
	// FileManagerActionCallbacks,
	FileManagerSystemState
	// StorageBackend
} from './types';
import type { SystemInformation } from '$lib/types/models';
import { basename } from '$lib/utils/path/helpers';
import { showError, showSuccess } from '$lib/utils/ui/notifications';
import { Logger } from '$lib/services';

export async function fetchFileManagerSystemState(apiClient: any): Promise<FileManagerSystemState> {
	try {
		const probeEndpoint = `/rest/fs/list?dir=${encodeURIComponent('/sdcard')}`;
		await apiClient.get(probeEndpoint);
	} catch (error) {
		Logger.debug('SD card probe request failed (expected when no card present).', error);
	}

	try {
		const data = await apiClient.get('/rest/systemStatus');

		if (!data) {
			Logger.error('Received invalid storage status payload.', data);
			return createDefaultState();
		}

		return deriveSystemState(data as SystemInformation);
	} catch (error) {
		Logger.error('Failed to load storage status', error);
		return createDefaultState();
	}
}

export function createFileManagerActions(
	{
		defaultPath,
		directoryCache,
		sdcardMountPath,
		checkIfDirectory,
		callbacks,
		apiClient
	}: CreateFileManagerActionsOptions,
	{
		fetchSystemState = fetchFileManagerSystemState
	}: { fetchSystemState?: typeof fetchFileManagerSystemState } = {}
) {
	async function refreshSystemState() {
		const next = await fetchSystemState(apiClient);
		callbacks.setSystemState(next);
	}

	async function loadDirectory(path: string) {
		callbacks.setIsLoading(true);
		callbacks.setErrorMessage(null);

		try {
			const data = await apiClient.get(`/rest/fs/list?dir=${encodeURIComponent(path)}`);

			const files: FileEntry[] = (data?.files ?? []).map((file: any) => ({
				...file,
				type: file.directory ? 'directory' : file.size === 0 ? 'unknown' : 'file'
			}));

			files.forEach((entry: FileEntry) => {
				directoryCache.set(entry.name, entry.type === 'directory');
			});

			callbacks.setCurrentPath(path);
			callbacks.setEntries(files);
			callbacks.setSelectedBackend(path.startsWith(sdcardMountPath) ? 'sdcard' : 'littlefs');

			if (path.startsWith(sdcardMountPath)) {
				void refreshSystemState();
			}

			const pending = files.filter((entry: FileEntry) => entry.type === 'unknown');

			if (pending.length) {
				await Promise.allSettled(
					pending.map(async (entry: FileEntry) => {
						const isDir = await checkIfDirectory(entry.name);
						entry.type = isDir ? 'directory' : 'file';
					})
				);
				callbacks.setEntries([...files]);
			}

			const state = callbacks.getSystemState();
			if (!state.hasSdCard && detectSdCardFromListing(path, files)) {
				callbacks.onSdCardDetected();
			}
		} catch (error) {
			Logger.error('Failed to load directory', error);
			callbacks.setErrorMessage('Failed to load directory contents.');
		} finally {
			callbacks.setIsLoading(false);
		}
	}

	async function downloadEntry(entry: FileEntry) {
		try {
			const response = await apiClient.fetch(
				`/rest/fs/download?path=${encodeURIComponent(entry.name)}`,
				{
					method: 'GET',
					headers: {
						Accept: 'application/octet-stream'
					}
				}
			);

			if (!response.ok) {
				showError('Failed to download file.');
				return;
			}

			const blob = await response.blob();
			const url = URL.createObjectURL(blob);
			const link = document.createElement('a');
			link.href = url;
			link.download = basename(entry.name);
			document.body.appendChild(link);
			link.click();
			document.body.removeChild(link);
			URL.revokeObjectURL(url);
		} catch (error) {
			Logger.error('Failed to download file', error);
			showError('Failed to download file.');
		}
	}

	async function refreshCurrentDirectory() {
		const path = callbacks.getCurrentPath() || defaultPath;
		await Promise.all([loadDirectory(path), refreshSystemState()]);
	}

	async function deleteEntry(entry: FileEntry) {
		try {
			const data = await apiClient.delete(`/rest/fs/remove?path=${encodeURIComponent(entry.name)}`);

			if ((data as any)?.ok !== false) {
				showSuccess('Entry removed successfully.');
				await refreshCurrentDirectory();
			} else {
				showError('Failed to remove entry.');
			}
		} catch (error) {
			Logger.error('Failed to remove entry', error);
			showError('Failed to remove entry.');
		}
	}

	async function handleUpload() {
		const files = callbacks.getUploadFiles();
		if (!files || files.length === 0) {
			return;
		}

		callbacks.setUploading(true);

		try {
			const file = files[0];
			const backend = callbacks.getSelectedBackend();
			const fallbackPath = getBackendMountPath(backend);
			const targetPath = callbacks.getCurrentPath() || fallbackPath;
			const endpoint = `/rest/fs/upload?backend=${backend}&path=${encodeURIComponent(targetPath)}`;

			const formData = new FormData();
			formData.append('file', file);

			const response = await apiClient.fetch(endpoint, {
				method: 'POST',
				body: formData
			});

			if (response.ok) {
				showSuccess('File uploaded successfully.');
				callbacks.setUploadFiles(null);
				await refreshCurrentDirectory();
			} else {
				showError('Failed to upload file.');
			}
		} catch (error) {
			Logger.error('Failed to upload file', error);
			showError('Failed to upload file.');
		} finally {
			callbacks.setUploading(false);
		}
	}

	return {
		loadDirectory,
		downloadEntry,
		deleteEntry,
		handleUpload,
		refreshSystemState
	};
}

import type { SystemInformation } from '$lib/types/models';

export type StorageBackend = 'littlefs' | 'sdcard';

export type EntryType = 'file' | 'directory' | 'unknown';

export type RawFileEntry = {
	name: string;
	size: number;
	directory?: boolean;
};

export type FileEntry = RawFileEntry & {
	type: EntryType;
};

export type FileListResponse = {
	files: RawFileEntry[];
};

export type StorageBackendStatus = {
	backend: StorageBackend;
	label: string;
	mountPath: string;
	available: boolean;
	mounted: boolean;
};

export type FileManagerSystemState = {
	hasSdCard: boolean;
	backends: StorageBackendStatus[];
	systemInformation: SystemInformation | null;
};

export type FileManagerActionCallbacks = {
	setIsLoading(value: boolean): void;
	setErrorMessage(message: string | null): void;
	setCurrentPath(path: string): void;
	setEntries(entries: FileEntry[]): void;
	setSelectedBackend(backend: StorageBackend): void;
	getCurrentPath(): string;
	getSelectedBackend(): StorageBackend;
	getUploadFiles(): FileList | null;
	setUploadFiles(files: FileList | null): void;
	setUploading(value: boolean): void;
	getSystemState(): FileManagerSystemState;
	setSystemState(state: FileManagerSystemState): void;
	onSdCardDetected(): void;
};

export interface CreateFileManagerActionsOptions {
	defaultPath: string;
	directoryCache: Map<string, boolean>;
	sdcardMountPath: string;
	apiClient: any;
	checkIfDirectory(path: string): Promise<boolean>;
	callbacks: FileManagerActionCallbacks;
}

import type { SystemInformation } from '$lib/types/models';
import {
	type FileEntry,
	type FileManagerSystemState,
	type StorageBackend,
	type StorageBackendStatus
} from './types';

const STORAGE_BACKEND_METADATA: Record<StorageBackend, { label: string; mountPath: string }> = {
	littlefs: { label: 'LittleFS', mountPath: '/' },
	sdcard: { label: 'microSD Card', mountPath: '/sdcard' }
};

const DEFAULT_SYSTEM_STATE: FileManagerSystemState = {
	hasSdCard: false,
	backends: [
		{
			backend: 'littlefs',
			label: STORAGE_BACKEND_METADATA.littlefs.label,
			mountPath: STORAGE_BACKEND_METADATA.littlefs.mountPath,
			available: true,
			mounted: true
		},
		{
			backend: 'sdcard',
			label: STORAGE_BACKEND_METADATA.sdcard.label,
			mountPath: STORAGE_BACKEND_METADATA.sdcard.mountPath,
			available: false,
			mounted: false
		}
	],
	systemInformation: null
};

export function createDefaultState(): FileManagerSystemState {
	return {
		hasSdCard: false,
		backends: DEFAULT_SYSTEM_STATE.backends.map((backend) => ({ ...backend })),
		systemInformation: null
	};
}

function resolveMetrics(metrics: any, fallbackAvailable: boolean) {
	const available = metrics?.available ?? metrics?.mounted ?? fallbackAvailable;
	const mounted = metrics?.mounted ?? metrics?.available ?? false;
	const total = metrics?.total ?? 0;
	return { available: Boolean(available), mounted: Boolean(mounted), total: Number(total) };
}

export function deriveSystemState(info?: SystemInformation | null): FileManagerSystemState {
	if (!info) {
		return createDefaultState();
	}

	const littlefsStatus = (() => {
		const metrics = (info as any).storage?.littlefs;
		const resolved = resolveMetrics(metrics, true);
		return {
			backend: 'littlefs' as StorageBackend,
			label: 'LittleFS',
			mountPath: '/littlefs',
			available: !!metrics,
			mounted: resolved.total > 0
		};
	})();

	const sdCardStatus = (() => {
		const metrics = (info as any).storage?.sdcard;
		const resolved = resolveMetrics(metrics, false);
		return {
			backend: 'sdcard' as const,
			label: STORAGE_BACKEND_METADATA.sdcard.label,
			mountPath: STORAGE_BACKEND_METADATA.sdcard.mountPath,
			available: resolved.available,
			mounted: resolved.mounted
		} satisfies StorageBackendStatus;
	})();

	const hasSdCard = sdCardStatus.available || sdCardStatus.mounted;

	return {
		hasSdCard,
		backends: [littlefsStatus, sdCardStatus],
		systemInformation: info
	} satisfies FileManagerSystemState;
}

export function markSdCardPresent(state: FileManagerSystemState): FileManagerSystemState {
	const updatedBackends = state.backends.map((backend) =>
		backend.backend === 'sdcard'
			? {
					...backend,
					available: true
				}
			: backend
	);

	return {
		...state,
		hasSdCard: true,
		backends: updatedBackends
	} satisfies FileManagerSystemState;
}

export function detectSdCardFromListing(path: string, files: FileEntry[]): boolean {
	if (path !== '/') {
		return false;
	}

	return files.some((entry) => {
		if (!entry.directory) {
			return false;
		}

		const normalized = entry.name.replace(/\/+$/, '');
		return normalized === '/sdcard' || normalized === 'sdcard';
	});
}

export function getBackendLabel(backend: StorageBackend): string {
	return STORAGE_BACKEND_METADATA[backend].label;
}

export function getBackendMountPath(backend: StorageBackend): string {
	return STORAGE_BACKEND_METADATA[backend].mountPath;
}

import { get, writable } from 'svelte/store';
import {
	createFileManagerActions,
	deriveSystemState,
	getBackendMountPath,
	markSdCardPresent,
	type FileEntry,
	type FileListResponse,
	type FileManagerSystemState,
	type StorageBackend
} from '$lib/services/fileManager';
import type { SystemInformation } from '$lib/types/models';
import { parentPath } from '$lib/utils/path/helpers';
import { Logger } from '$lib/services';
import {
	formatEntrySize as baseFormatEntrySize,
	getBackendOptions as deriveBackendOptions,
	getEntryLabel as baseGetEntryLabel,
	type BackendOption
} from '../selectors/formatters';
export type { BackendOption } from '../selectors/formatters';

interface CreateFileManagerStateOptions {
	initialPath?: string;
	initialEntries?: FileEntry[];
	initialSystemInformation?: SystemInformation | null;
	apiClient?: any;
}

const DEFAULT_PATH = '/';

export function createFileManagerState({
	initialPath = DEFAULT_PATH,
	initialEntries = [],
	initialSystemInformation = null,
	apiClient
}: CreateFileManagerStateOptions = {}) {
	const directoryCache = new Map<string, boolean>([[DEFAULT_PATH, true]]);
	const sdcardMountPath = getBackendMountPath('sdcard');

	const currentPath = writable(initialPath);
	const entries = writable<FileEntry[]>(initialEntries);
	const isLoading = writable(false);
	const errorMessage = writable<string | null>(null);
	const uploadFiles = writable<FileList | null>(null);
	const uploading = writable(false);
	const systemState = writable<FileManagerSystemState>(
		deriveSystemState(initialSystemInformation ?? null)
	);
	const selectedBackend = writable<StorageBackend>(
		initialPath.startsWith(sdcardMountPath) ? 'sdcard' : 'littlefs'
	);

	function setUploadFiles(files: FileList | null) {
		uploadFiles.set(files);
	}

	async function checkIfDirectory(path: string): Promise<boolean> {
		if (directoryCache.has(path)) {
			return directoryCache.get(path) ?? false;
		}

		if (path === DEFAULT_PATH) {
			directoryCache.set(path, true);
			return true;
		}

		try {
			const data = await apiClient.get(`/rest/fs/list?dir=${encodeURIComponent(path)}`);
			const files = data?.files ?? [];
			let isDir = false;
			if (files.length === 0) {
				isDir = true;
			} else if (files.length === 1 && files[0]?.name === path) {
				isDir = false;
			} else {
				isDir = true;
			}
			directoryCache.set(path, isDir);
			return isDir;
		} catch (error) {
			Logger.error(`[FileManagerState] Failed to determine entry type for ${path}`, error);
			directoryCache.set(path, false);
			return false;
		}
	}

	const { loadDirectory, downloadEntry, deleteEntry, handleUpload, refreshSystemState } =
		createFileManagerActions({
			defaultPath: DEFAULT_PATH,
			directoryCache,
			sdcardMountPath,
			apiClient,
			async checkIfDirectory(path: string) {
				return checkIfDirectory(path);
			},
			callbacks: {
				setIsLoading(value) {
					isLoading.set(value);
				},
				setErrorMessage(message) {
					errorMessage.set(message);
				},
				setCurrentPath(path) {
					currentPath.set(path);
				},
				setEntries(value) {
					entries.set(value);
				},
				setSelectedBackend(backend) {
					selectedBackend.set(backend);
				},
				getCurrentPath() {
					return get(currentPath);
				},
				getSelectedBackend() {
					return get(selectedBackend);
				},
				getUploadFiles() {
					return get(uploadFiles);
				},
				setUploadFiles(files) {
					uploadFiles.set(files);
				},
				setUploading(value) {
					uploading.set(value);
				},
				getSystemState() {
					return get(systemState);
				},
				setSystemState(state) {
					systemState.set(state);
				},
				onSdCardDetected() {
					const state = get(systemState);
					systemState.set(markSdCardPresent(state));
				}
			}
		});

	async function ensureEntryType(entry: FileEntry): Promise<'file' | 'directory'> {
		if (entry.type === 'unknown') {
			const isDir = await checkIfDirectory(entry.name);
			entries.update((current) =>
				current.map((item) =>
					item.name === entry.name
						? {
								...item,
								type: isDir ? 'directory' : 'file'
							}
						: item
				)
			);
			return isDir ? 'directory' : 'file';
		}

		return entry.type === 'directory' ? 'directory' : 'file';
	}

	async function openEntry(entry: FileEntry) {
		const type = await ensureEntryType(entry);
		if (type === 'directory') {
			await loadDirectory(entry.name);
		} else {
			await downloadEntry(entry);
		}
	}

	async function goToParent() {
		const next = parentPath(get(currentPath));
		await loadDirectory(next);
	}

	async function refresh() {
		const path = get(currentPath);
		await Promise.all([loadDirectory(path), refreshSystemState()]);
	}

	function setSelectedBackend(backend: StorageBackend) {
		selectedBackend.set(backend);

		const path = get(currentPath);
		if (backend === 'sdcard') {
			if (!path.startsWith(sdcardMountPath)) {
				void loadDirectory(sdcardMountPath);
			}
		} else if (path.startsWith(sdcardMountPath)) {
			void loadDirectory(DEFAULT_PATH);
		}
	}

	function syncSystemInformation(info?: SystemInformation | null) {
		if (!info) {
			return;
		}

		const derived = deriveSystemState(info);
		const state = get(systemState);
		if (derived.hasSdCard && !state.hasSdCard) {
			systemState.set(derived);
		}
	}

	function formatEntrySize(entry: FileEntry): string {
		return baseFormatEntrySize(entry);
	}

	function getEntryLabel(entry: FileEntry): string {
		return baseGetEntryLabel(entry);
	}

	function getBackendOptions(): BackendOption[] {
		return deriveBackendOptions(get(systemState));
	}

	function canDeleteEntry(entry: FileEntry, canModify: boolean): boolean {
		return canModify && entry.name !== DEFAULT_PATH;
	}

	return {
		currentPath,
		entries,
		isLoading,
		errorMessage,
		uploadFiles,
		uploading,
		selectedBackend,
		systemState,
		loadDirectory,
		openEntry,
		downloadEntry,
		deleteEntry,
		handleUpload,
		refresh,
		goToParent,
		refreshSystemState,
		setUploadFiles,
		setSelectedBackend,
		syncSystemInformation,
		formatEntrySize,
		getEntryLabel,
		getBackendOptions,
		canDeleteEntry
	};
}

import { describe, expect, it } from 'vitest';

describe('design system barrel exports', () => {
	it('exposes tokens, variants, presets, and utilities', async () => {
		const designSystem = await import('../design-system');

		expect(designSystem.icon.wrapper.panel).toContain('rounded-2xl');
		expect(designSystem.semantic.page.container).toContain('space-y');

		expect(designSystem.getButtonClasses('ghost', 'sm')).toContain('btn-ghost');
		expect(designSystem.getButtonClasses('icon', 'lg')).toContain('btn-circle');
		expect(designSystem.getButtonClasses('unknown' as any, 'md')).toContain('btn-primary');

		expect(designSystem.getInputClasses(true, false, 'xs')).toContain('border-error');
		expect(designSystem.getInputClasses(false, true, 'lg')).toContain('max-w-xs');
		expect(designSystem.getInputClasses(true, true, 'sm')).toContain('border-error');
		expect(designSystem.cardVariants.interactive).toContain('hover:shadow-2xl');
		expect(designSystem.dialogVariants.md).toContain('max-w-md');
		expect(designSystem.formVariants.actions).toContain('justify-end');

		expect(designSystem.surfaceCard('px-4')).toContain('surface-card');
		expect(designSystem.surfacePanel('shadow')).toContain('surface-panel');
		expect(designSystem.detailTile('gap-2')).toContain('detail-tile');
		expect(designSystem.miniCard('gap-1')).toContain('mini-card');

		expect(designSystem.fileManagerStyles.headerBadge).toContain('badge');
		expect(designSystem.powerManagementStyles.badgeWithIcon).toContain('badge-outline');

		expect(designSystem.variants.button.primary).toContain('btn-primary');
	});
});

import { describe, expect, it } from 'vitest';

import { buttonVariants, getButtonClasses } from '../buttons';

describe('button variants', () => {
	it('exposes static variant map', () => {
		expect(buttonVariants.primary).toContain('btn-primary');
		expect(buttonVariants.icon.md).toContain('btn-circle');
	});

	it('computes button classes for all variants and sizes', () => {
		expect(getButtonClasses()).toBe(buttonVariants.primary);
		expect(getButtonClasses('secondary', 'lg')).toContain('btn-lg');
		expect(getButtonClasses('ghost', 'sm')).toContain('btn-sm');
		expect(getButtonClasses('danger', 'xs')).toContain('btn-xs');
		expect(getButtonClasses('success')).toContain('btn-success');
		expect(getButtonClasses('warning')).toContain('btn-warning');
		expect(getButtonClasses('accent')).toContain('btn-accent');
		expect(getButtonClasses('neutral')).toContain('btn-neutral');
		expect(getButtonClasses('icon', 'lg')).toBe(buttonVariants.icon.lg);
		expect(getButtonClasses('unknown' as any)).toBe(buttonVariants.primary);
	});
});
